import { apiClient, unwrap, type BffResponse } from '../api';

export interface FormOption {
  value: string;
  label: string;
}

export interface ErpFormInitData {
  materialGroupOptions: FormOption[];
  customerGroupOptions: FormOption[];
  unitOptions: FormOption[];
  taxRateOptions: FormOption[];
  currencyOptions: FormOption[];
  warehouseOptions: FormOption[];
  departmentOptions: FormOption[];
  voucherStatusOptions: FormOption[];
  purchaseInvoiceTypeOptions: FormOption[];
  processingLevelOptions: FormOption[];
  activeStatusOptions: FormOption[];
  customerTypeOptions: FormOption[];
  paymentMethodOptions: FormOption[];
  legalTypeOptions: FormOption[];
  vatRegisteredOptions: FormOption[];
  customerBankAccountKindOptions: FormOption[];
}

interface BffErpFormInitDataDto {
  materialGroupOptions?: FormOption[];
  customerGroupOptions?: FormOption[];
  unitOptions?: FormOption[];
  taxRateOptions?: FormOption[];
  currencyOptions?: FormOption[];
  warehouseOptions?: FormOption[];
  departmentOptions?: FormOption[];
  voucherStatusOptions?: FormOption[];
  purchaseInvoiceTypeOptions?: FormOption[];
  processingLevelOptions?: FormOption[];
  activeStatusOptions?: FormOption[];
  customerTypeOptions?: FormOption[];
  paymentMethodOptions?: FormOption[];
  legalTypeOptions?: FormOption[];
  vatRegisteredOptions?: FormOption[];
  customerBankAccountKindOptions?: FormOption[];
}

const mapOpts = (items?: FormOption[]): FormOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

const emptyInit = (): ErpFormInitData => ({
  materialGroupOptions: [],
  customerGroupOptions: [],
  unitOptions: [],
  taxRateOptions: [],
  currencyOptions: [],
  warehouseOptions: [],
  departmentOptions: [],
  voucherStatusOptions: [],
  purchaseInvoiceTypeOptions: [],
  processingLevelOptions: [],
  activeStatusOptions: [],
  customerTypeOptions: [],
  paymentMethodOptions: [],
  legalTypeOptions: [],
  vatRegisteredOptions: [],
  customerBankAccountKindOptions: [],
});

const _cache = new Map<string, Promise<ErpFormInitData>>();

const _fetchInitData = async (formName: string): Promise<ErpFormInitData> => {
  const res = await apiClient.get<BffResponse<BffErpFormInitDataDto>>(
    `/forms/init-data?formName=${encodeURIComponent(formName)}`,
  );
  const dto = unwrap(res);
  return {
    materialGroupOptions: mapOpts(dto.materialGroupOptions),
    customerGroupOptions: mapOpts(dto.customerGroupOptions),
    unitOptions: mapOpts(dto.unitOptions),
    taxRateOptions: mapOpts(dto.taxRateOptions),
    currencyOptions: mapOpts(dto.currencyOptions),
    warehouseOptions: mapOpts(dto.warehouseOptions),
    departmentOptions: mapOpts(dto.departmentOptions),
    voucherStatusOptions: mapOpts(dto.voucherStatusOptions),
    purchaseInvoiceTypeOptions: mapOpts(dto.purchaseInvoiceTypeOptions),
    processingLevelOptions: mapOpts(dto.processingLevelOptions),
    activeStatusOptions: mapOpts(dto.activeStatusOptions),
    customerTypeOptions: mapOpts(dto.customerTypeOptions),
    paymentMethodOptions: mapOpts(dto.paymentMethodOptions),
    legalTypeOptions: mapOpts(dto.legalTypeOptions),
    vatRegisteredOptions: mapOpts(dto.vatRegisteredOptions),
    customerBankAccountKindOptions: mapOpts(dto.customerBankAccountKindOptions),
  };
};

export const voucherInitService = {
  getInitData: (formName: string): Promise<ErpFormInitData> => {
    if (!_cache.has(formName)) {
      _cache.set(
        formName,
        _fetchInitData(formName).catch(err => {
          _cache.delete(formName);
          return Promise.reject(err);
        }),
      );
    }
    return _cache.get(formName)!;
  },
  clearCache: () => _cache.clear(),
};

export { emptyInit };
