import React from 'react';
import { Input, type SelectOption } from '@linm-soft-org/linm-web-common-components';
import { resolveInitOptionLabel } from '../../../utils/initOptionLabel';
import type { CustomerDto } from '../../../services/master/models';
import {
  type CustomerBankAccountLine,
  type CustomerDiscountTermLine,
  isSupplierLikeCustomerType,
  mapBankLinesFromDto,
  mapDiscountLinesFromDto,
} from '../../../services/master/customerDetailModels';
import { formTextFieldLock } from '../../../utils/formViewLock';
import { CustomerBankAccountGrid, CustomerDiscountTermGrid } from './CustomerDetailGrids';
import styles from './CustomerDetailGrids.module.css';
import pageStyles from '../../../styles/erpPage.module.css';

type CustomerViewDetailProps = {
  testIdPrefix: string;
  form: Partial<CustomerDto>;
  bankLines: CustomerBankAccountLine[];
  discountLines: CustomerDiscountTermLine[];
  detailLoading?: boolean;
  paymentMethodOptions: SelectOption[];
  legalTypeOptions: SelectOption[];
  vatRegisteredOptions: SelectOption[];
  bankKindOptions: SelectOption[];
};

const ViewField: React.FC<{
  label: string;
  value: string;
  testId: string;
  fullRow?: boolean;
}> = ({ label, value, testId, fullRow }) => (
  <div
    className={fullRow ? pageStyles.formGridFullRow : pageStyles.field}
    data-testid={testId}
  >
    <label className={pageStyles.label}>{label}</label>
    <Input value={value} readOnly {...formTextFieldLock(true)} />
  </div>
);

function formatMoney(value?: number): string {
  if (value == null || Number.isNaN(value) || value === 0) return '';
  return value.toLocaleString('vi-VN');
}

export const CustomerViewDetail: React.FC<CustomerViewDetailProps> = ({
  testIdPrefix,
  form,
  bankLines,
  discountLines,
  detailLoading = false,
  paymentMethodOptions,
  legalTypeOptions,
  vatRegisteredOptions,
  bankKindOptions,
}) => {
  const showSupplierDetail = isSupplierLikeCustomerType(form.customerType);
  const paymentLabel = resolveInitOptionLabel(paymentMethodOptions, form.paymentMethod);
  const vatLabel = resolveInitOptionLabel(
    vatRegisteredOptions,
    form.vatRegistered === true ? 'true' : form.vatRegistered === false ? 'false' : '',
  );

  if (!showSupplierDetail) return null;

  return (
    <div className={pageStyles.viewReadOnlySection} data-testid={`${testIdPrefix}-view-detail`}>
      <h4 className={styles.sectionTitle}>Thông tin chung (NCC)</h4>
      <div className={pageStyles.formGrid}>
        <ViewField
          label="Tên thường gọi"
          value={form.shortName ?? ''}
          testId={`${testIdPrefix}-view-shortName`}
          fullRow
        />
        <ViewField
          label="Nhóm đối tượng 1"
          value={form.group1 ?? ''}
          testId={`${testIdPrefix}-view-group1`}
        />
        <ViewField
          label="Nhóm đối tượng 2"
          value={form.group2 ?? ''}
          testId={`${testIdPrefix}-view-group2`}
        />
        <ViewField label="Email" value={form.email ?? ''} testId={`${testIdPrefix}-view-email`} />
        <ViewField
          label="Người liên hệ"
          value={form.contactPerson ?? ''}
          testId={`${testIdPrefix}-view-contactPerson`}
        />
        <ViewField
          label="Hình thức thanh toán"
          value={paymentLabel}
          testId={`${testIdPrefix}-view-paymentMethod`}
        />
        <ViewField
          label="Tuổi nợ (ngày)"
          value={form.paymentTermDays != null && form.paymentTermDays > 0
            ? String(form.paymentTermDays)
            : ''}
          testId={`${testIdPrefix}-view-paymentTermDays`}
        />
        <ViewField
          label="Thời gian GH (ngày)"
          value={form.gracePeriodDays != null && form.gracePeriodDays > 0
            ? String(form.gracePeriodDays)
            : ''}
          testId={`${testIdPrefix}-view-gracePeriodDays`}
        />
        <ViewField
          label="Nhóm đối tượng 3"
          value={form.group3 ?? ''}
          testId={`${testIdPrefix}-view-group3`}
        />
        <ViewField
          label="Nhóm đối tượng 4"
          value={form.group4 ?? ''}
          testId={`${testIdPrefix}-view-group4`}
        />
        <ViewField
          label="Đăng ký VAT"
          value={vatLabel}
          testId={`${testIdPrefix}-view-vatRegistered`}
        />
        <ViewField
          label="Hạn mức công nợ"
          value={formatMoney(form.creditLimit)}
          testId={`${testIdPrefix}-view-creditLimit`}
        />
        <ViewField
          label="Quận / huyện"
          value={form.district ?? ''}
          testId={`${testIdPrefix}-view-district`}
        />
        <ViewField
          label="Tỉnh / thành phố"
          value={form.province ?? ''}
          testId={`${testIdPrefix}-view-province`}
        />
        <ViewField
          label="TK ngân hàng (mặc định)"
          value={[form.bankName, form.bankAccount].filter(Boolean).join(' — ')}
          testId={`${testIdPrefix}-view-bankDefault`}
        />
        <ViewField
          label="Điện thoại kế toán"
          value={form.accountingPhone ?? ''}
          testId={`${testIdPrefix}-view-accountingPhone`}
        />
        <ViewField
          label="Email đối chiếu công nợ"
          value={form.reconciliationEmail ?? ''}
          testId={`${testIdPrefix}-view-reconciliationEmail`}
        />
        <ViewField
          label="Tên saler"
          value={form.salesContactName ?? ''}
          testId={`${testIdPrefix}-view-salesContactName`}
        />
        <ViewField
          label="Điện thoại saler"
          value={form.salesContactPhone ?? ''}
          testId={`${testIdPrefix}-view-salesContactPhone`}
        />
        <ViewField
          label="Ghi chú"
          value={form.notes ?? ''}
          testId={`${testIdPrefix}-view-notes`}
          fullRow
        />
      </div>

      <h4 className={styles.sectionTitle}>
        Hợp đồng &amp; chiết khấu theo thời gian
        {detailLoading ? ' — đang tải…' : ''}
      </h4>
      <CustomerDiscountTermGrid
        rows={discountLines}
        viewOnly
        testIdPrefix={testIdPrefix}
      />

      <h4 className={styles.sectionTitle}>Thông tin chuyển khoản</h4>
      <CustomerBankAccountGrid
        rows={bankLines}
        viewOnly
        testIdPrefix={testIdPrefix}
        bankKindOptions={bankKindOptions}
      />
    </div>
  );
};

export function extractDetailGrids(detail: Record<string, unknown> | null | undefined): {
  bankLines: CustomerBankAccountLine[];
  discountLines: CustomerDiscountTermLine[];
} {
  if (!detail) {
    return { bankLines: [], discountLines: [] };
  }
  const bankRaw = (detail.bankAccounts ?? detail.BankAccounts) as Array<Record<string, unknown>> | undefined;
  const discountRaw = (detail.discountTerms ?? detail.DiscountTerms) as Array<Record<string, unknown>> | undefined;
  return {
    bankLines: mapBankLinesFromDto(bankRaw),
    discountLines: mapDiscountLinesFromDto(discountRaw),
  };
}
