import { createDocumentHistoryClient } from '@linm-soft-org/linm-web-common-components';

/** ERP WebService — document history API (chứng từ + danh mục master). */
export const erpDocumentHistoryClient = createDocumentHistoryClient({
  basePath: '/document-history',
  pageSize: 20,
});

/** documentType BE — map catalogKind → DocumentTypes.MasterCatalog* */
export const masterCatalogDocumentTypes = {
  units: 'MasterCatalogUnit',
  currencies: 'MasterCatalogCurrency',
  warehouses: 'MasterCatalogWarehouse',
  departments: 'MasterCatalogDepartment',
  customers: 'MasterCatalogCustomer',
  materials: 'MasterCatalogMaterial',
  'material-groups': 'MasterCatalogMaterialGroup',
  'customer-groups': 'MasterCatalogCustomerGroup',
  'transfer-templates': 'MasterCatalogTransferTemplate',
  'allocation-templates': 'MasterCatalogAllocationTemplate',
  'tools-equipment': 'MasterCatalogToolsEquipment',
  'expense-items': 'MasterCatalogExpenseItem',
  accounts: 'MasterCatalogAccount',
  'company-bank-accounts': 'MasterCatalogCompanyBankAccount',
} as const;

export type MasterCatalogDocumentKind = keyof typeof masterCatalogDocumentTypes;

export function masterCatalogDocumentType(catalogKind: string): string | undefined {
  return masterCatalogDocumentTypes[catalogKind as MasterCatalogDocumentKind];
}
